cd /tmp/binlog-reader && cat > Program.cs << 'EOF'
using System;
using Microsoft.Build.Logging.StructuredLogger;
using Microsoft.Build.Framework;

var reader = new BinLogReader();
var records = reader.ReadRecords("/tmp/sv-dbb8ff0432f34a07a2168b301811b8c9/build.binlog");

foreach (var record in records)
{
    if (record.Args is BuildErrorEventArgs error)
    {
        Console.WriteLine($"ERROR [{error.ProjectFile}] {error.File}({error.LineNumber},{error.ColumnNumber}): {error.Code}: {error.Message}");
    }
    else if (record.Args is BuildWarningEventArgs warning && warning.Code != null && (warning.Code.StartsWith("NU") || warning.Code.StartsWith("MSB")))
    {
        Console.WriteLine($"WARN  [{warning.ProjectFile}] {warning.Code}: {warning.Message}");
    }
    else if (record.Args is BuildFinishedEventArgs finished)
    {
        Console.WriteLine($"BUILD FINISHED: Succeeded={finished.Succeeded}");
    }
    else if (record.Args is ProjectFinishedEventArgs projFinished)
    {
        Console.WriteLine($"PROJECT FINISHED: {System.IO.Path.GetFileName(projFinished.ProjectFile)} Succeeded={projFinished.Succeeded}");
    }
}
EOF
dotnet run 2>&1 | grep -v "^/tmp/binlog-reader.*warning NU"

