using System;
using Microsoft.Build.Logging.StructuredLogger;
using Microsoft.Build.Framework;

var reader = new BinLogReader();
var records = reader.ReadRecords("/tmp/sv-dbb8ff0432f34a07a2168b301811b8c9/build.binlog");

foreach (var record in records)
{
    if (record.Args is TaskCommandLineEventArgs cmdLine && cmdLine.TaskName == "Csc" && cmdLine.ProjectFile?.Contains("Services") == true)
    {
        // Extract source files from command line
        var cmd = cmdLine.CommandLine;
        Console.WriteLine("Services Csc references:");
        foreach (var part in cmd.Split(' '))
        {
            if (part.StartsWith("/reference:") || part.Contains("Newtonsoft"))
                Console.WriteLine("  " + part);
        }
        break;
    }
}
EOF
